            const purchase = document.getElementById('purchase');
            if (purchase) {
                purchase.innerHTML = `<a target=""_blank"" href=""/Purchase/PurchaseReceipt/${product.PurchaseId}"">Purchase Details <i class=""fal fa-long-arrow-right""></i></a>`;
